styles:
:root{--bg:#111827;--card:#1f2937;--line:#374151;--text:#e5e7eb;--muted:#9ca3af;--ok:#34d399;--bad:#fb7185;--accent:#60a5fa}
*{box-sizing:border-box}html,body{margin:0;background:var(--bg)!important;color:var(--text)!important;font:14px/1.55 system-ui,"Microsoft YaHei",sans-serif!important}
main{max-width:1180px;margin:auto;padding:24px}h1{font-size:24px;margin:0 0 8px;color:#f8fafc!important}.lede{color:var(--muted)!important;margin:0 0 16px}
.summary{display:grid;grid-template-columns:repeat(5,minmax(110px,1fr));gap:8px;margin:14px 0}.metric{background:var(--card);color:var(--text)!important;border:1px solid var(--line);border-radius:10px;padding:10px}.metric span{color:#cbd5e1!important}.metric b{display:block;font-size:20px;color:#f8fafc!important}
#suite-root .yb-stage table{width:100%;border-collapse:collapse;background:#fff;color:#111827;border:1px solid #cbd5e1}#suite-root .yb-stage th,#suite-root .yb-stage td{position:static;border-bottom:1px solid #cbd5e1;padding:8px;text-align:left;vertical-align:top;background:#fff;color:#111827}code{white-space:pre-wrap;word-break:break-word;color:#bfdbfe}
.yb-badge{display:inline-block;padding:2px 7px;border-radius:999px;background:#374151;color:#e5e7eb}.foot{color:var(--muted);margin-top:12px}
.yb-grid{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:16px}.yb-card{min-width:0;border:1px solid var(--line);border-radius:16px;background:var(--card);color:var(--text);padding:16px;overflow:hidden}.yb-card.pass{border-color:#166534}.yb-card.fail{border-color:#9f1239}.yb-head{display:flex;justify-content:space-between;gap:10px;align-items:flex-start}.yb-head h2{font-size:18px;margin:0;color:#f8fafc}.yb-meta{display:grid;grid-template-columns:1fr 1fr;gap:8px;margin:10px 0}.yb-meta div{padding:8px;border-radius:8px;background:#111827}.yb-meta span{display:block;color:var(--muted);font-size:11px}.yb-stage{position:relative;min-height:190px;padding:14px;border-radius:12px;background:#f8fafc;color:#111827;overflow:auto;isolation:isolate}.yb-stage [data-library-artifact]{max-width:100%}.yb-checks{margin:10px 0 0;padding:0;list-style:none}.yb-checks li{margin-top:5px;padding:7px;border-radius:7px;background:#111827}.yb-checks .ok{color:var(--ok)}.yb-checks .bad{color:var(--bad)}.result-box{padding:14px;border:2px solid #0f766e;border-radius:12px;background:#ecfeff;color:#134e4a;white-space:pre-wrap;overflow-wrap:anywhere}.yb-download,.download{display:inline-block;padding:10px 14px;border-radius:9px;background:#2563eb;color:white;text-decoration:none}.static-dialog{display:grid;gap:8px;width:min(100%,360px);padding:16px;border-radius:12px;background:white;box-shadow:0 8px 28px #0003}.static-dialog h3,.static-dialog p{margin:0}.bootstrap-proof{padding:14px;border:1px solid #86efac;border-radius:8px;background:#f0fdf4;color:#166534}.document-proof{display:grid;gap:8px;justify-items:start}.foot{grid-column:1/-1}@media(max-width:900px){.yb-grid{grid-template-columns:1fr}.summary{grid-template-columns:repeat(2,1fr)}.yb-meta{grid-template-columns:1fr}}
